 14â†’
 15â†’export const CLIENTS: ReadonlySet<string> = new Set(['codex', 'claude', 'gemini'])
 16â†’export const TEXT_BLOCK_TYPES: ReadonlySet<string> = new Set(['input_text', 'output_text', 'text'])
 17â†’export const SKIP_BLOCK_TYPES: ReadonlySet<string> = new Set(['thinking', 'reasoning'])
 18â†’export const TOOL_USE_TYPES: ReadonlySet<string> = new Set(['tool_use'])
 19â†’export const TOOL_RESULT_TYPES: ReadonlySet<string> = new Set(['tool_result'])
