 29â†’export function slugify(value: string, fallback = 'session'): string {
 30â†’  const asciiValue = value.replace(/[^\x00-\x7F]/g, '').toLowerCase()
 31â†’  const slug = asciiValue.replace(/[^a-z0-9._-]+/g, '-').replace(/^[-._]+|[-._]+$/g, '')
 32â†’  return slug || fallback
 33â†’}
