 35â†’export function sha256File(filePath: string): string {
 36â†’  const data = readFileSync(filePath)
 37â†’  return createHash('sha256').update(data).digest('hex')
 38â†’}
 39â†’
 40â†’export function contentHash(text: string): string {
 41â†’  return createHash('sha256').update(text, 'utf8').digest('hex').slice(0, 16)
 42â†’}
 43â†’
 44â†’export function normalizeTimestamp(value: unknown, fallback?: string | null): string {
 45â†’  if (typeof value === 'number') {
 46â†’    // Always treat as Unix seconds (matching Python's datetime.fromtimestamp)
 47â†’    const d = new Date(value * 1000)
 48â†’    return formatUtcIso(d)
 49â†’  }
 50â†’
 51â†’  if (value instanceof Date) {
 52â†’    return formatUtcIso(value)
 53â†’  }
 54â†’
 55â†’  if (typeof value === 'string') {
 56â†’    const text = value.trim()
 57â†’    if (!text) {
 58â†’      return fallback ?? normalizeTimestamp(new Date())
 59â†’    }
 60â†’    const parsed = parseIsoTimestamp(text)
 61â†’    if (parsed !== null) {
 62â†’      return formatUtcIso(parsed)
 63â†’    }
 64â†’    return text
 65â†’  }
 66â†’
 67â†’  return fallback ?? normalizeTimestamp(new Date())
 68â†’}
