 83â†’export function parseIsoTimestamp(value: string): Date | null {
 84â†’  if (!value) return null
 85â†’  let candidate = value
 86â†’  if (candidate.endsWith('Z')) {
 87â†’    candidate = candidate.slice(0, -1) + '+00:00'
 88â†’  } else if (!/[+-]\d{2}:\d{2}$/.test(candidate) && !/[+-]\d{4}$/.test(candidate)) {
 89â†’    // No timezone offset â€” treat as UTC (matching Python behavior)
 90â†’    candidate = candidate + '+00:00'
 91â†’  }
 92â†’  const d = new Date(candidate)
 93â†’  if (isNaN(d.getTime())) return null
 94â†’  return d
 95â†’}
