 98â†’  const d = parseIsoTimestamp(timestamp)
 99â†’  if (d === null) return ['unknown', 'unknown']
100â†’  const year = d.getUTCFullYear().toString()
101â†’  const month = (d.getUTCMonth() + 1).toString().padStart(2, '0')
102â†’  return [year, month]
103â†’}
